		/// config.periods                  = 3;<br/>
		/// ma_device device;<br/>
		/// result = ma_device_init(<br/>
		/// &context<br/>
		/// , <br/>
		/// &config<br/>
		/// , <br/>
		/// &device<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// ```<br/>
