		/// ma_uint32 playbackDeviceCount;<br/>
		/// result = ma_context_get_devices(<br/>
		/// &context<br/>
		/// , <br/>
		/// &pPlaybackDeviceInfos<br/>
		/// , <br/>
		/// &playbackDeviceCount<br/>
		/// , NULL, NULL);<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
