		/// &context<br/>
		/// , <br/>
		/// &config<br/>
		/// , <br/>
		/// &device<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// ```<br/>
