		/// config.pMyUserData       = pMyUserData;<br/>
		/// ma_device device;<br/>
		/// ma_result result = ma_device_init(NULL, <br/>
		/// &config<br/>
		/// , <br/>
		/// &device<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
