		/// and the format used internally by the backend. If you pass in 0 for the sample format, channel count, sample rate _and_ channel map, data transmission will run<br/>
		/// on an optimized pass-through fast path. You can retrieve the format, channel count and sample rate by inspecting the `playback/capture.format`,<br/>
		/// `playback/capture.channels` and `sampleRate` members of the device object.<br/>
		/// When compiling for UWP you must ensure you call this function on the main UI thread because the operating system may need to present the user with a message<br/>
		/// asking for permissions. Please refer to the official documentation for ActivateAudioInterfaceAsync() for more information.<br/>
		/// ALSA Specific: When initializing the default device, requesting shared mode will try using the "dmix" device for playback and the "dsnoop" device for capture.<br/>
		/// If these fail it will try falling back to the "hw" device.<br/>
		/// Example 1 - Simple Initialization<br/>
		/// ---------------------------------<br/>
		/// This example shows how to initialize a simple playback device using a standard configuration. If you are just needing to do simple playback from the default<br/>
		/// playback device this is usually all you need.<br/>
		/// ```c<br/>
		/// ma_device_config config = ma_device_config_init(ma_device_type_playback);<br/>
		/// config.playback.format   = ma_format_f32;<br/>
		/// config.playback.channels = 2;<br/>
		/// config.sampleRate        = 48000;<br/>
		/// config.dataCallback      = ma_data_callback;<br/>
		/// config.pMyUserData       = pMyUserData;<br/>
		/// ma_device device;<br/>
		/// ma_result result = ma_device_init(NULL, <br/>
		/// &config<br/>
		/// , <br/>
		/// &device<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// ```<br/>
		/// Example 2 - Advanced Initialization<br/>
		/// -----------------------------------<br/>
		/// This example shows how you might do some more advanced initialization. In this hypothetical example we want to control the latency by setting the buffer size<br/>
		/// and period count. We also want to allow the user to be able to choose which device to output from which means we need a context so we can perform device<br/>
		/// enumeration.<br/>
		/// ```c<br/>
		/// ma_context context;<br/>
		/// ma_result result = ma_context_init(NULL, 0, NULL, <br/>
		/// &context<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// ma_device_info* pPlaybackDeviceInfos;<br/>
		/// ma_uint32 playbackDeviceCount;<br/>
		/// result = ma_context_get_devices(<br/>
		/// &context<br/>
		/// , <br/>
		/// &pPlaybackDeviceInfos<br/>
		/// , <br/>
		/// &playbackDeviceCount<br/>
		/// , NULL, NULL);<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// // ... choose a device from pPlaybackDeviceInfos ...<br/>
		/// ma_device_config config = ma_device_config_init(ma_device_type_playback);<br/>
		/// config.playback.pDeviceID       = pMyChosenDeviceID;    // <br/>
		/// <<br/>
		/// -- Get this from the `id` member of one of the `ma_device_info` objects returned by ma_context_get_devices().<br/>
		/// config.playback.format          = ma_format_f32;<br/>
		/// config.playback.channels        = 2;<br/>
		/// config.sampleRate               = 48000;<br/>
		/// config.dataCallback             = ma_data_callback;<br/>
		/// config.pUserData                = pMyUserData;<br/>
		/// config.periodSizeInMilliseconds = 10;<br/>
		/// config.periods                  = 3;<br/>
		/// ma_device device;<br/>
		/// result = ma_device_init(<br/>
		/// &context<br/>
		/// , <br/>
		/// &config<br/>
		/// , <br/>
		/// &device<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// ```<br/>
		/// See Also<br/>
		/// --------<br/>
		/// ma_device_config_init()<br/>
		/// ma_device_uninit()<br/>
		/// ma_device_start()<br/>
		/// ma_context_init()<br/>
		/// ma_context_get_devices()<br/>
		/// ma_context_enumerate_devices()<br/>
		/// </summary>
		public static MaResult DeviceInit(ref MaContext pContext, MaDeviceConfigPtr pConfig, ref MaDevice pDevice)
		{
			fixed (MaContext* ppContext = &pContext)
			{
				fixed (MaDevice* ppDevice = &pDevice)
				{
					MaResult ret = DeviceInitNative((MaContext*)ppContext, (MaDeviceConfig*)pConfig, (MaDevice*)ppDevice);
					return ret;
				}
			}
		}

		/// <summary>
