		/// &context<br/>
		/// , <br/>
		/// &pPlaybackDeviceInfos<br/>
		/// , <br/>
		/// &playbackDeviceCount<br/>
		/// , NULL, NULL);<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error<br/>
		/// }<br/>
		/// // ... choose a device from pPlaybackDeviceInfos ...<br/>
		/// ma_device_config config = ma_device_config_init(ma_device_type_playback);<br/>
